import{_ as e,a as t,b as i}from"./chunks/支持留言.NiGCLVdp.js";import{_ as s,o,c as n,a2 as l}from"./chunks/framework.DnrXFDHb.js";const k=JSON.parse('{"title":"Blog","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/Other/blog.md","filePath":"ms-MY/Other/blog.md","lastUpdated":1781962217000}'),p={name:"ms-MY/Other/blog.md"};function d(r,a,g,c,u,m){return o(),n("div",null,[...a[0]||(a[0]=[l('<h1 id="blog" tabindex="-1">Blog <a class="header-anchor" href="#blog" aria-label="Permalink to &quot;Blog&quot;">​</a></h1><p>Blog feature menambah halaman blog standalone kepada ImgBed site anda.</p><p>Selepas diaktifkan, visitors boleh membuka:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-domain.com/blog/</span></span></code></pre></div><p><img src="'+e+'" alt="Blog homepage" loading="lazy"></p><p>Blog ini diadaptasi daripada open-source project <a href="https://github.com/LyraVoid/Mizuki" target="_blank" rel="noreferrer">LyraVoid/Mizuki</a>. ImgBed rewrite dan mengintegrasikannya dengan Vue supaya ia boleh berjalan sebagai sebahagian daripada image hosting site.</p><h2 id="di-mana-untuk-configure" tabindex="-1">Di Mana Untuk Configure <a class="header-anchor" href="#di-mana-untuk-configure" aria-label="Permalink to &quot;Di Mana Untuk Configure&quot;">​</a></h2><p>Blog settings berada di:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Blog</span></span></code></pre></div><p><img src="'+t+'" alt="Blog settings" loading="lazy"></p><h2 id="first-time-setup" tabindex="-1">First-Time Setup <a class="header-anchor" href="#first-time-setup" aria-label="Permalink to &quot;First-Time Setup&quot;">​</a></h2><ol><li>Hidupkan <code>Enable</code>.</li><li>Pilih GitHub account yang digunakan untuk menyimpan blog configuration.</li><li>Klik <code>Update Blog</code>.</li><li>Tunggu success message.</li><li>Buka <code>https://your-domain.com/blog/</code> untuk melihat blog.</li></ol><p>Pada penggunaan pertama, ImgBed menyediakan private GitHub repository di bawah account yang dipilih:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Repository ini menyimpan blog settings dan article content.</p><h2 id="menulis-posts" tabindex="-1">Menulis Posts <a class="header-anchor" href="#menulis-posts" aria-label="Permalink to &quot;Menulis Posts&quot;">​</a></h2><p>Edit blog posts dalam private GitHub repository:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>imgbed-blog-config</span></span></code></pre></div><p>Typical workflow:</p><ol><li>Buka GitHub.</li><li>Masuk ke private repository <code>imgbed-blog-config</code>.</li><li>Edit atau add post files.</li><li>Commit changes.</li><li>Kembali ke ImgBed admin panel dan klik <code>Update Blog</code>, atau klik logo di penjuru kiri atas blog homepage tiga kali untuk trigger blog update.</li></ol><p><code>Update Blog</code> tidak overwrite content yang anda tulis. Ia initialize repository apabila perlu dan refresh blog cache.</p><h2 id="supported-features" tabindex="-1">Supported Features <a class="header-anchor" href="#supported-features" aria-label="Permalink to &quot;Supported Features&quot;">​</a></h2><p>Blog menyokong common blog features seperti post lists, categories, tags, archives, search, dark mode dan language switching.</p><p>Ia juga menyokong comments dan visit statistics.</p><p><img src="'+i+'" alt="Blog comments" loading="lazy"></p><p>Comments muncul di bawah posts. Visitors boleh submit avatar, nickname, email dan comment content.</p><p>Visit statistics menunjukkan post views dan site visits, membantu anda memahami blog traffic.</p><h2 id="url" tabindex="-1">URL <a class="header-anchor" href="#url" aria-label="Permalink to &quot;URL&quot;">​</a></h2><p>Blog sentiasa served di bawah <code>/blog/</code>.</p><p>Contohnya, jika ImgBed domain anda ialah:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com</span></span></code></pre></div><p>Blog URL ialah:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://image.example.com/blog/</span></span></code></pre></div><p>Selepas blog disabled, visitors tidak lagi boleh mengakses blog page.</p>',34)])])}const v=s(p,[["render",d]]);export{k as __pageData,v as default};
